// frontend/src/pages/LoginPage.tsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../services/api';

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const { data } = await authService.login({ username, password });
      localStorage.setItem('user', JSON.stringify(data));

      if (data.role === 'admin') navigate('/admin');
      else navigate('/store');
    } catch (error) {
      alert('Hatalı giriş!');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-100 to-slate-200 p-4">
      {/* Kart Konteynırı */}
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl shadow-slate-300/50 p-8 space-y-8 border border-white">

        {/* Logo veya Başlık Alanı */}
        <div className="text-center space-y-2">
          <div className="inline-flex items-center justify-center w-16 h-16 bg-blue-600 rounded-2xl mb-4 shadow-lg shadow-blue-200">
            <span className="text-white text-3xl font-bold">K</span>
          </div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight">Hoş Geldiniz</h2>
          <p className="text-slate-500 font-medium">Kitabevi Demo Sistemine Giriş Yapın</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          {/* Kullanıcı Adı Alanı */}
          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700 ml-1">Kullanıcı Adı</label>
            <input 
              type="text" 
              placeholder="Örn: admin" 
              onChange={(e) => setUsername(e.target.value)}
              className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all placeholder:text-slate-400"
            />
          </div>

          {/* Şifre Alanı */}
          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700 ml-1">Şifre</label>
            <input 
              type="password" 
              placeholder="••••••••" 
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-5 py-3 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all placeholder:text-slate-400"
            />
          </div>

          {/* Giriş Butonu */}
          <button 
            type="submit"
            className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-2xl shadow-xl shadow-blue-200 transition-all active:scale-[0.98] focus:ring-4 focus:ring-blue-500/30"
          >
            Giriş Yap
          </button>
        </form>

        {/* Alt Bilgi */}
        <div className="text-center">
          <p className="text-sm text-slate-400 font-medium italic">
            "Kamyonet" Lojistik & Yazılım Sistemleri
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
